solution:
[asy]
size(150);
pair A, B, C, D, O;
O=(0,0);
A=(-1,0);
B=(0,-1);
C=(1,0);
D=(.5,.866);
draw(circle(O, 1));
dot(O);
draw(A--B--C--D--A--C);
